34	/// Banner string emitted as the first line of normal command runs
35	/// and shown at the top of subcommand `--help` output. Built from
36	/// `Cargo.toml`'s name + version at compile time so it stays in
37	/// sync with the bumped version.
38	const BANNER: &str = concat!(env!("CARGO_PKG_NAME"), " ", env!("CARGO_PKG_VERSION"));
39	
40	/// Top-level about line — name, version, and the project tagline
41	/// on a single line. Used as the top-level `about` so `vc-x1 -h`
42	/// reads as one banner-plus-tagline header instead of two stacked
43	/// lines.
44	const TOP_ABOUT: &str = concat!(
45	    env!("CARGO_PKG_NAME"),
46	    " ",
47	    env!("CARGO_PKG_VERSION"),
48	    " - jj workspace tooling"
49	);
50	
51	/// Build the clap command tree with `BANNER` set as `before_help`
52	/// on every subcommand (transitively). Top-level skips `before_help`
53	/// because its own `about` already carries the name+version+tagline.
54	/// Walks via `mut_subcommand` so individual subcommand
55	/// `#[command(long_about = ...)]` blocks don't have to repeat the
56	/// banner text.
57	fn cli_with_banner() -> clap::Command {
58	    fn add_to_subs(mut cmd: clap::Command) -> clap::Command {
59	        let names: Vec<String> = cmd
60	            .get_subcommands()
61	            .map(|c| c.get_name().to_string())
62	            .collect();
63	        for name in names {
64	            cmd = cmd.mut_subcommand(name, add_with_banner);
65	        }
66	        cmd
67	    }
68	    fn add_with_banner(mut cmd: clap::Command) -> clap::Command {
69	        cmd = cmd.before_help(BANNER);
70	        let names: Vec<String> = cmd
71	            .get_subcommands()
72	            .map(|c| c.get_name().to_string())
73	            .collect();
74	        for name in names {
75	            cmd = cmd.mut_subcommand(name, add_with_banner);
76	        }
77	        cmd
78	    }
79	    add_to_subs(Cli::command())
80	}
