            target: work_path.to_string_lossy().into_owned(),
            name: None,
            account: AccountOption::default(),
            repo: RepoOption {
                repo: Some(RepoSelector {
                    category: "local".to_string(),
                    value: Some(base.to_string_lossy().into_owned()),
                }),
            },
            scope: ScopeOption {
                scope: ScopeKind::CodeBot,
