24	/// - `Code` — the primary (app) repo.
25	/// - `Bot` — the Claude Code session repo (typically at `.claude/`).
26	#[derive(Copy, Clone, Debug, PartialEq, Eq, ValueEnum)]
27	pub enum Side {
28	    Code,
29	    Bot,
30	}
31	
32	/// Parsed `--scope` value.
33	///
