35	/// - `Single(_)` — explicit single-repo mode at the given path.
36	#[derive(Clone, Debug, PartialEq, Eq)]
37	pub enum Scope {
38	    Roles(Vec<Side>),
39	    // Staged: production code starts constructing this in 0.42.0-2
