        assert!(!s.is_code_only());
        assert!(s.is_bot_only());
        assert!(!s.is_both());
    }

    #[test]
    fn both_code_then_bot() {
        let s = Scope::Roles(vec![Side::Code, Side::Bot]);
        assert!(!s.is_code_only());
        assert!(!s.is_bot_only());
        assert!(s.is_both());
