    fn empty_roles() {
        let s = Scope::Roles(vec![]);
        assert!(s.is_empty());
        assert!(!s.is_code_only());
        assert!(!s.is_bot_only());
        assert!(!s.is_both());
    }

    #[test]
    fn single_helpers_all_false() {
